mapper.insert:
INSERT INTO article_outbox (id, author_id, article_id, published_at)
SELECT #{id}, #{authorId}, #{articleId}, #{publishedAt}
WHERE NOT EXISTS (
    SELECT 1
    FROM article_outbox
    WHERE author_id = #{authorId}
      AND article_id = #{articleId}
)

INSERT INTO user_inbox (id, user_id, author_id, article_id, published_at)
SELECT #{id}, #{userId}, #{authorId}, #{articleId}, #{publishedAt}
WHERE NOT EXISTS (
    SELECT 1
    FROM user_inbox
    WHERE user_id = #{userId}
      AND article_id = #{articleId}
)

mapper.select:
SELECT id, NULL AS user_id, author_id, article_id, published_at, created_at
FROM article_outbox
WHERE author_id = #{authorId}
ORDER BY published_at DESC, article_id DESC
LIMIT #{limit}

SELECT COUNT(*)
FROM article_outbox
WHERE author_id = #{authorId}

SELECT id, user_id, author_id, article_id, published_at, created_at
FROM user_inbox
WHERE user_id = #{userId}
ORDER BY published_at DESC, article_id DESC
LIMIT #{limit}

mapper.delete:
DELETE FROM user_inbox
WHERE user_id = #{userId}
  AND author_id = #{authorId}
